Code:
public int centeredAverage(int[] nums)
{
    int max = nums[0];
    int min = nums[0];
    int sum = nums[0];

    for (int i = 1; i < nums.length; i++)
    {
        if (nums[i] > max) max = nums[i];
        if (nums[i] < min) min = nums[i];
        sum += nums[i];
    }

    sum -= max;
    sum -= min;

    return sum / (nums.length - 2);
}

